import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { usePersistence } from './usePersistence';


const ACCENT = '#FF9100';

function initials(b) {
  return ((b.name[0] || '') + (b.last[0] || '')).toUpperCase();
}

export default function BarberoPerfil() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { barberos } = usePersistence();

  const b = barberos.find(x => String(x.id) === String(id));

  if (!b) {
    return (
      <div style={{ minHeight: '100vh', background: 'var(--ink)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1rem' }}>
        <i className="ti ti-user-off" style={{ fontSize: '3rem', color: 'var(--text3)' }} />
        <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '1.5rem', color: 'var(--text2)' }}>
          Barbero no encontrado
        </div>
        <button onClick={() => navigate('/')} style={btnBack}>
          Volver al panel
        </button>
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', background: 'var(--ink)', display: 'flex', flexDirection: 'column' }}>

      {/* topbar */}
      <div style={{
        background: 'var(--ink2)',
        borderBottom: '1px solid var(--border)',
        padding: '0 2rem',
        height: 62,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      }}>
        <img src="/logo.png" alt="Nórdico Barbería" style={{ height: 40, width: 'auto' }} />
        <button onClick={() => navigate('/')} style={btnBack}>
          <i className="ti ti-arrow-left" style={{ marginRight: 6 }} />
          Panel
        </button>
      </div>

      {/* hero */}
      <div style={{
        background: 'var(--ink2)',
        borderBottom: '1px solid var(--border)',
        padding: '3rem 2rem',
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        textAlign: 'center',
        position: 'relative', overflow: 'hidden',
      }}>
        {/* accent line top */}
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 4, background: `linear-gradient(90deg, transparent, ${ACCENT}, transparent)` }} />

        {/* avatar */}
        <div style={{
          width: 100, height: 100, borderRadius: '50%',
          background: 'var(--ink3)',
          border: `3px solid ${ACCENT}66`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontFamily: "'Cormorant Garamond', serif",
          fontSize: '2.5rem', fontWeight: 600, color: ACCENT,
          marginBottom: '1.25rem',
          overflow: 'hidden', flexShrink: 0,
        }}>
          {b.avatar
            ? <img src={b.avatar} alt={b.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            : initials(b)
          }
        </div>

        <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '2.2rem', fontWeight: 300, color: 'var(--text)', lineHeight: 1.1 }}>
          {b.name} {b.last}
        </div>
        <div style={{ fontSize: '0.72rem', letterSpacing: '0.25em', textTransform: 'uppercase', color: ACCENT, marginTop: 8 }}>
          {b.role}
        </div>

        <div style={{ display: 'flex', gap: 8, marginTop: 14, flexWrap: 'wrap', justifyContent: 'center' }}>
          <Pill>{b.status === 'active' ? 'Activo' : 'Inactivo'}</Pill>
          <Pill>{b.branch}</Pill>
        </div>
      </div>

      {/* content */}
      <div style={{ flex: 1, maxWidth: 560, width: '100%', margin: '0 auto', padding: '2rem 1.5rem', display: 'flex', flexDirection: 'column', gap: '2rem' }}>

        {b.bio && (
          <Section title="Sobre mí">
            <p style={{ fontSize: '0.95rem', color: 'var(--text2)', lineHeight: 1.8 }}>{b.bio}</p>
          </Section>
        )}

        {b.skills.length > 0 && (
          <Section title="Especialidades">
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {b.skills.map((s, i) => (
                <span key={i} style={{
                  fontSize: '0.75rem', letterSpacing: '0.08em',
                  padding: '5px 12px', borderRadius: 2,
                  background: `${ACCENT}15`, color: ACCENT,
                  border: `1px solid ${ACCENT}40`,
                }}>
                  {s}
                </span>
              ))}
            </div>
          </Section>
        )}

        <Section title="Contacto">
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {b.phone && (
              <a href={`https://wa.me/${b.phone.replace(/\D/g, '')}`} target="_blank" rel="noreferrer" style={contactRow}>
                <div style={contactIcon}><i className="ti ti-brand-whatsapp" /></div>
                <div>
                  <div style={contactLabel}>WhatsApp</div>
                  <div style={contactValue}>{b.phone}</div>
                </div>
                <i className="ti ti-arrow-right" style={{ marginLeft: 'auto', color: 'var(--text3)', fontSize: 14 }} />
              </a>
            )}
            {b.ig && (
              <a href={`https://instagram.com/${b.ig.replace('@', '')}`} target="_blank" rel="noreferrer" style={contactRow}>
                <div style={contactIcon}><i className="ti ti-brand-instagram" /></div>
                <div>
                  <div style={contactLabel}>Instagram</div>
                  <div style={contactValue}>{b.ig}</div>
                </div>
                <i className="ti ti-arrow-right" style={{ marginLeft: 'auto', color: 'var(--text3)', fontSize: 14 }} />
              </a>
            )}
            {b.hora && (
              <div style={{ ...contactRow, cursor: 'default' }}>
                <div style={contactIcon}><i className="ti ti-clock" /></div>
                <div>
                  <div style={contactLabel}>Horario</div>
                  <div style={contactValue}>{b.hora}</div>
                </div>
              </div>
            )}
            <div style={{ ...contactRow, cursor: 'default' }}>
              <div style={contactIcon}><i className="ti ti-map-pin" /></div>
              <div>
                <div style={contactLabel}>Sede</div>
                <div style={contactValue}>{b.branch}</div>
              </div>
            </div>
          </div>
        </Section>
      </div>

      {/* portfolio */}
      {b.photos && b.photos.length > 0 && (
        <div style={{ maxWidth: 560, width: '100%', margin: '0 auto', padding: '0 1.5rem 2rem' }}>
          <div style={{
            fontSize: '0.63rem', letterSpacing: '0.22em',
            textTransform: 'uppercase', color: 'var(--text3)',
            marginBottom: 12, display: 'flex', alignItems: 'center', gap: 10,
          }}>
            Portafolio
            <div style={{ flex: 1, height: 1, background: 'var(--border)' }} />
          </div>
          <Carousel photos={b.photos} />
        </div>
      )}

      {/* footer */}
      <div style={{
        padding: '1.5rem',
        borderTop: '1px solid var(--border)',
        textAlign: 'center',
      }}>
        <img src="/logo.png" alt="Nórdico Barbería" style={{ height: 32, width: 'auto', opacity: 0.5 }} />
      </div>
    </div>
  );
}

function Carousel({ photos }) {
  const [current, setCurrent] = useState(0);
  const [lightbox, setLightbox] = useState(null);

  const prev = () => setCurrent(i => (i - 1 + photos.length) % photos.length);
  const next = () => setCurrent(i => (i + 1) % photos.length);

  // touch swipe support
  const touchStart = React.useRef(null);
  const handleTouchStart = (e) => { touchStart.current = e.touches[0].clientX; };
  const handleTouchEnd = (e) => {
    if (touchStart.current === null) return;
    const diff = touchStart.current - e.changedTouches[0].clientX;
    if (Math.abs(diff) > 40) diff > 0 ? next() : prev();
    touchStart.current = null;
  };

  return (
    <>
      {/* main slide */}
      <div
        style={{ position: 'relative', borderRadius: 6, overflow: 'hidden', background: 'var(--ink2)', userSelect: 'none' }}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        <div style={{ aspectRatio: '4/3', overflow: 'hidden' }}>
          <img
            src={photos[current]}
            alt={`trabajo ${current + 1}`}
            onClick={() => setLightbox(current)}
            style={{
              width: '100%', height: '100%', objectFit: 'cover',
              cursor: 'zoom-in', transition: 'opacity 0.25s',
            }}
          />
        </div>

        {/* arrows */}
        {photos.length > 1 && (
          <>
            <button onClick={prev} style={{ ...arrowBtn, left: 10 }}>
              <i className="ti ti-chevron-left" />
            </button>
            <button onClick={next} style={{ ...arrowBtn, right: 10 }}>
              <i className="ti ti-chevron-right" />
            </button>
          </>
        )}

        {/* counter */}
        <div style={{
          position: 'absolute', bottom: 10, right: 12,
          fontSize: '0.7rem', color: 'rgba(255,255,255,0.7)',
          background: 'rgba(0,0,0,0.5)', padding: '2px 8px', borderRadius: 20,
          letterSpacing: '0.08em',
        }}>
          {current + 1} / {photos.length}
        </div>
      </div>

      {/* thumbnails */}
      {photos.length > 1 && (
        <div style={{ display: 'flex', gap: 6, marginTop: 8, overflowX: 'auto', paddingBottom: 2 }}>
          {photos.map((src, i) => (
            <div
              key={i}
              onClick={() => setCurrent(i)}
              style={{
                width: 56, height: 56, flexShrink: 0, borderRadius: 3,
                overflow: 'hidden', cursor: 'pointer',
                border: `2px solid ${i === current ? ACCENT : 'transparent'}`,
                opacity: i === current ? 1 : 0.5,
                transition: 'all 0.15s',
              }}
            >
              <img src={src} alt={`miniatura ${i + 1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            </div>
          ))}
        </div>
      )}

      {/* lightbox */}
      {lightbox !== null && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.95)',
            zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center',
            padding: '1rem',
          }}
        >
          <button
            onClick={(e) => { e.stopPropagation(); setLightbox(i => (i - 1 + photos.length) % photos.length); }}
            style={{ ...arrowBtn, position: 'fixed', left: 16, top: '50%', transform: 'translateY(-50%)' }}
          >
            <i className="ti ti-chevron-left" />
          </button>

          <img
            src={photos[lightbox]}
            alt={`trabajo ${lightbox + 1}`}
            onClick={e => e.stopPropagation()}
            style={{ maxWidth: '90vw', maxHeight: '85vh', objectFit: 'contain', borderRadius: 4 }}
          />

          <button
            onClick={(e) => { e.stopPropagation(); setLightbox(i => (i + 1) % photos.length); }}
            style={{ ...arrowBtn, position: 'fixed', right: 16, top: '50%', transform: 'translateY(-50%)' }}
          >
            <i className="ti ti-chevron-right" />
          </button>

          <button
            onClick={() => setLightbox(null)}
            style={{ ...arrowBtn, position: 'fixed', top: 16, right: 16, transform: 'none' }}
          >
            <i className="ti ti-x" />
          </button>

          <div style={{
            position: 'fixed', bottom: 20,
            fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)',
            letterSpacing: '0.1em',
          }}>
            {lightbox + 1} / {photos.length}
          </div>
        </div>
      )}
    </>
  );
}

const arrowBtn = {
  position: 'absolute', top: '50%', transform: 'translateY(-50%)',
  background: 'rgba(0,0,0,0.6)', border: `1px solid rgba(255,255,255,0.15)`,
  color: '#fff', width: 36, height: 36, borderRadius: '50%',
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  cursor: 'pointer', fontSize: 16, zIndex: 10,
};


function Section({ title, children }) {
  return (
    <div>
      <div style={{
        fontSize: '0.63rem', letterSpacing: '0.22em',
        textTransform: 'uppercase', color: 'var(--text3)',
        marginBottom: 12, display: 'flex', alignItems: 'center', gap: 10,
      }}>
        {title}
        <div style={{ flex: 1, height: 1, background: 'var(--border)' }} />
      </div>
      {children}
    </div>
  );
}

function Pill({ children }) {
  return (
    <span style={{
      fontSize: '0.62rem', letterSpacing: '0.15em',
      textTransform: 'uppercase', padding: '4px 10px', borderRadius: 2,
      background: 'rgba(106,98,88,0.15)', color: 'var(--text3)',
      border: '1px solid rgba(106,98,88,0.2)',
    }}>
      {children}
    </span>
  );
}

const btnBack = {
  background: 'transparent',
  border: '1px solid var(--border)',
  color: 'var(--text2)',
  padding: '7px 14px',
  fontSize: '0.78rem',
  borderRadius: 3,
  cursor: 'pointer',
  display: 'flex', alignItems: 'center',
};

const contactRow = {
  display: 'flex', alignItems: 'center', gap: 14,
  background: 'var(--ink2)',
  border: '1px solid var(--border)',
  borderRadius: 4, padding: '12px 16px',
  textDecoration: 'none', color: 'inherit',
  transition: 'border-color 0.15s',
};

const contactIcon = {
  width: 38, height: 38, borderRadius: '50%',
  background: `${ACCENT}15`,
  border: `1px solid ${ACCENT}35`,
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  color: ACCENT, fontSize: 18, flexShrink: 0,
};

const contactLabel = {
  fontSize: '0.65rem', letterSpacing: '0.12em',
  textTransform: 'uppercase', color: 'var(--text3)', marginBottom: 2,
};

const contactValue = {
  fontSize: '0.88rem', color: 'var(--text)',
};
